import subprocess

def convert_document(input_file, output_file, format):
    if format == 'pdf':
        command = f'libreoffice --headless --convert-to pdf {input_file} -o {output_file}'
    elif format == 'docx':
        command = f'libreoffice --headless --outdir {output_file}.odt {input_file}'
        command += ' && libreoffice --headless --convert-to docx {output_file}.odt -o {output_file}'
    else:
        raise ValueError("Invalid format. Supported formats are pdf and docx.")

